#include <stdio.h>
#include <limits.h>
int main() {
    int T, N, K;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &K);
        int A[N], B[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &A[i], &B[i]);
        }
        int dp[N];
        dp[0] = A[0] * B[0];
        for (int i = 1; i < N; i++) {
            dp[i] = INT_MAX;
            for (int j = 1; j <= K && i - j >= 0; j++) {
                dp[i] = (dp[i] < (A[i] > A[i-j] ? A[i] : A[i-j]) * (B[i] > B[i-j] ? B[i] : B[i-j])) ? dp[i] : (A[i] > A[i-j] ? A[i] : A[i-j]) * (B[i] > B[i-j] ? B[i] : B[i-j]);
            }
        }
        printf("%d\n", dp[N-1]);
    }
    return 0;
}

