import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] A = new int[N];
            int[] B = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
                B[i] = sc.nextInt();
            }
            int[] dp = new int[N];
            dp[0] = A[0] * B[0];
            for (int i = 1; i < N; i++) {
                dp[i] = Integer.MAX_VALUE;
                for (int j = 1; j <= K && i - j >= 0; j++) {
                    dp[i] = (dp[i] < (A[i] > A[i-j] ? A[i] : A[i-j]) * (B[i] > B[i-j] ? B[i] : B[i-j])) ? dp[i] : (A[i] > A[i-j] ? A[i] : A[i-j]) * (B[i] > B[i-j] ? B[i] : B[i-j]);
                }
            }
            System.out.println(dp[N-1]);
        }
    }
}

