import sys
T = int(sys.stdin.readline())
for _ in range(T):
    N, K = map(int, sys.stdin.readline().split())
    A = [0]*N
    B = [0]*N
    for i in range(N):
        A[i], B[i] = map(int, sys.stdin.readline().split())
    dp = [0]*N
    dp[0] = A[0] * B[0]
    for i in range(1, N):
        dp[i] = float('inf')
        for j in range(1, K+1):
            if i - j >= 0:
                dp[i] = min(dp[i], max(A[i], A[i-j]) * max(B[i], B[i-j]))
    print(dp[N-1])

