while (T--) {
    let [N, K] = lines[i++].trim().split(' ').map(x => +x);
    let A = new Array(N);
    let B = new Array(N);
    for (let j = 0; j < N; j++) {
        [A[j], B[j]] = lines[i++].trim().split(' ').map(x => +x);
    }
    let dp = new Array(N);
    dp[0] = A[0] * B[0];
    for (let j = 1; j < N; j++) {
        dp[j] = Infinity;
        for (let k = 1; k <= K && j - k >= 0; k++) {
            dp[j] = Math.min(dp[j], Math.max(A[j], A[j-k]) * Math.max(B[j], B[j-k]));
        }
    }
    console.log(dp[N-1]);
}
